previewCss:
.darma-loader-darma-custom-487 {color: var(--loader-color, #0284c7);
  --loader-secondary-color: #7dd3fc;
  --loader-bg: #ffffff;
   width: 35px;
   height: 70px;
   position: relative;
}
.darma-loader-darma-custom-487:after  {
  content: "";
   position: absolute;
   inset: 0;
   padding: 3px 5px;
   border-top: 1px solid var(--loader-secondary-color, #7dd3fc);
   border-bottom: 4px solid var(--loader-secondary-color, #7dd3fc);
   background: linear-gradient(var(--loader-secondary-color, #7dd3fc) 0 0) bottom no-repeat content-box, var(--loader-secondary-color, #7dd3fc);
   mix-blend-mode: darken;
   animation: darma-loader-darma-custom-487-l1 1.5s infinite linear;
}
.darma-loader-darma-custom-487:before  {
  content: "";
   position: absolute;
   inset: -18px calc(50% - 2px) 8px;
   background: var(--loader-secondary-color, #7dd3fc);
   transform-origin: bottom;
   transform: rotate(8deg);
}
@keyframes darma-loader-darma-custom-487-l1  {
  0% {background-size: 100% 100%}
100% {background-size: 100% 5%}
}

